// Browser: three 'concurrent' fetch calls, all fire simultaneously
const t0 = Date.now();
const [users, posts, comments] = await Promise.all([
  fetch('/api/users').then(r => r.json()),   // ~200ms in Web API
  fetch('/api/posts').then(r => r.json()),   // ~200ms in Web API
  fetch('/api/comments').then(r => r.json()) // ~200ms in Web API
]);
// All three run concurrently in Web APIs — total ~200ms, not 600ms
console.log(`Done in ${Date.now() - t0}ms`);

