// Web Worker — true parallel JS thread
const worker = new Worker('heavy-task.js');
worker.postMessage({ data: largeArray }); // send data
worker.onmessage = (e) => {
  console.log('Worker result:', e.data); // receive result
  // Worker ran in parallel — main thread was never blocked
};
